#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(param);

my $log_dir = '/path/to/log/directory';  # Set this to your log directory

# Get the filename from query parameters
my $filename = param('logfile');

# Check if the filename is provided and sanitize it
if (!$filename) {
    die "No logfile specified";
}

# Resolve the full path to the file
my $full_path = "$log_dir/$filename";

# Canonicalize the path to prevent directory traversal
use File::Spec;
$full_path = File::Spec->canonpath($full_path);

# Check if the resolved path is within the intended directory
if (!File::Spec->file_name_is_absolute($full_path) || $full_path !~ m/^$log_dir\//) {
    die "Invalid logfile specified";
}

# Open and read the log file
open(my $fh, '<', $full_path) or die "Cannot open $filename: $!";

print "Content-type: text/plain\n\n";

while (my $line = <$fh>) {
    print $line;
}

close($fh);